import { urlFor } from '../../sanity/lib/image'
import Image from 'next/image'

const Hero = ({ heading, subheading, backgroundImage, services, primaryButton, secondaryButton, smallLine }: { heading: string, subheading: string, backgroundImage: any, services: any[], primaryButton?: string, secondaryButton?: string, smallLine?: string }) => {
  const sundayServices = services.filter(service => service.day === 'Sunday');
  const midweekServices = services.filter(service => service.day !== 'Sunday');

  return (
    <section className="relative h-screen flex items-center justify-center">
      {backgroundImage && (
        <Image
          src={urlFor(backgroundImage).url()}
          alt="Hero background"
          fill
          className="object-cover"
          priority
        />
      )}
      <div className="absolute inset-0 bg-gray-900 bg-opacity-60"></div>
      <div className="text-center text-white z-10 px-4 max-w-4xl mx-auto">
        <h1 className="text-3xl md:text-5xl lg:text-6xl font-bold mb-2 font-inter">{heading}</h1>
        <p className="text-lg md:text-xl mb-4 font-inter">{subheading}</p>
        {smallLine && <p className="text-sm md:text-base mb-6">{smallLine}</p>}
        <div className="mb-6">
          <p className="text-sm md:text-base mb-2">Join us for worship:</p>
          <div className="flex flex-col md:flex-row justify-center items-center space-y-1 md:space-y-0 md:space-x-4 text-sm md:text-base">
            {sundayServices.length > 0 && (
              <div>
                <span className="font-semibold">Sunday:</span> {sundayServices.map(s => `${s.title} ${s.time}`).join(', ')}
              </div>
            )}
            {midweekServices.length > 0 && (
              <div>
                <span className="font-semibold">Midweek:</span> {midweekServices.map(s => `${s.title} ${s.time}`).join(', ')}
              </div>
            )}
          </div>
        </div>
        <div className="flex flex-col space-y-4 sm:flex-row sm:space-y-0 sm:space-x-4 justify-center">
          <button className="bg-red-600 text-white px-6 py-3 rounded-lg font-inter hover:bg-red-700 transition-colors text-base font-semibold">
            {primaryButton || 'Watch Live'}
          </button>
          <button className="bg-white text-gray-900 px-6 py-3 rounded-lg font-inter hover:bg-gray-100 transition-colors text-base font-semibold">
            {secondaryButton || 'Plan Your Visit'}
          </button>
        </div>
      </div>
    </section>
  );
};

export default Hero;
